// Compute a simple moving average and momentum signal
const items = $input.all().map(i => i.json);
const closes = items.map(j => Number(j.price)).filter(n => !isNaN(n));
const sma = closes.slice(-20).reduce((a, b) => a + b, 0) / Math.min(20, closes.length);
const last = closes[closes.length - 1];
const momentum = closes.length > 5 ? last - closes[closes.length - 6] : 0;
return [{ json: { sma20: Math.round(sma * 100) / 100, last, momentum, signal: last > sma && momentum > 0 ? 'bullish' : 'neutral' } }];

// Build a stable idempotency key per asset (djb2 hash, no deps)
function hash(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0;
  return h.toString(16);
}
return $input.all().map(item => {
  const j = item.json;
  return { json: { ...j, idempotencyKey: hash([j.symbol, j.price].join('|')) } };
});

// Compare current metrics with the previous snapshot
const current = $input.first().json;
const prev = $('Load Previous Snapshot').first().json || {};
const drift = {};
for (const k of Object.keys(current)) {
  if (typeof current[k] === 'number' && typeof prev[k] === 'number' && prev[k] !== 0) {
    drift[k] = Math.round(((current[k] - prev[k]) / prev[k]) * 1000) / 10;
  }
}
return [{ json: { ...current, driftPct: drift, hasDrift: Object.values(drift).some(v => Math.abs(v) > 10) } }];
